import Foundation
import Metal

// This example shows the structure of Metal shader code
print("Metal Shader Pipeline Structure:\n")

let shaderCode = """
// Vertex input structure
struct VertexIn {
    float3 position;
    float4 color;
};

// Vertex output / Fragment input
struct VertexOut {
    float4 position [[position]];
    float4 color;
};

// Vertex shader
vertex VertexOut vertexShader(
    const VertexIn *vertices [[buffer(0)]],
    uint vertexID [[vertex_id]]
) {
    VertexOut out;
    out.position = float4(vertices[vertexID].position, 1.0);
    out.color = vertices[vertexID].color;
    return out;
}

// Fragment shader
fragment float4 fragmentShader(
    VertexOut in [[stage_in]]
) {
    return in.color;
}
"""

print(shaderCode)

print("\n--- Swift Setup ---")

let setupCode = """
// Create Metal device
let device = MTLCreateSystemDefaultDevice()!

// Create render pipeline
let descriptor = MTLRenderPipelineDescriptor()
descriptor.vertexFunction = device.makeFunction(name: "vertexShader")
descriptor.fragmentFunction = device.makeFunction(name: "fragmentShader")
descriptor.colorAttachments[0].pixelFormat = .bgra8Unorm

let pipeline = try! device.makeRenderPipelineState(descriptor: descriptor)
"""

print(setupCode)
